import{_ as e,o,c as r,ag as t}from"./chunks/framework.DjqkqlVQ.js";const _=JSON.parse('{"title":"玄羁 人物 Mod","description":"","frontmatter":{},"headers":[],"relativePath":"mods/xuanji-character/index.md","filePath":"mods/xuanji-character/index.md","lastUpdated":1778341931000}'),i={name:"mods/xuanji-character/index.md"};function l(d,a,n,s,c,h){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="玄羁-人物-mod" tabindex="-1">玄羁 人物 Mod <a class="header-anchor" href="#玄羁-人物-mod" aria-label="Permalink to &quot;玄羁 人物 Mod&quot;">​</a></h1><p>玄羁是一个正在开发中的 杀戮尖塔2 自定义角色 Mod。她会以“羁绊”为核心玩法：玩家在一局中选择、组合并凑齐不同羁绊，让牌组从零散动作逐渐变成有明确节奏的联动体系。</p><p>状态：开发中<br> 作者：Jason Song<br> 类型：自定义角色 / 羁绊构筑<br> 是否影响玩法：是，会加入新角色和新的构筑方向。</p><h2 id="预告" tabindex="-1">预告 <a class="header-anchor" href="#预告" aria-label="Permalink to &quot;预告&quot;">​</a></h2><p>玄羁的设计方向不是单纯追求某一张牌的爆发，而是让玩家围绕多个羁绊标签做取舍。不同牌、遗物和战斗选择会推动羁绊逐渐成型；当组合达到关键条件时，牌组会获得更清晰的战斗节奏和更强的联动收益。</p><p>目前可以透露的重点：</p><ul><li>这是一个 杀戮尖塔2 自定义角色。</li><li>她会使用“羁绊”作为核心机制。</li><li>玩家需要在选牌、出牌和构筑过程中凑出羁绊。</li><li>不同羁绊会引导不同的战斗节奏和牌组方向。</li><li>具体卡牌、数值、UI 和完整规则仍在开发中，后续会按稳定程度逐步公开。</li></ul><h2 id="当前状态" tabindex="-1">当前状态 <a class="header-anchor" href="#当前状态" aria-label="Permalink to &quot;当前状态&quot;">​</a></h2><p>玄羁还处在开发阶段，页面暂时只放玩法预告，不展示角色界面、战斗界面或未定稿的具体规则。等基础体验稳定后，这里会补充更完整的角色介绍、发布信息和更新记录。</p><h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li>返回：<a href="/jasonsong-games/mods/">全部 Mod</a></li></ul>',11)])])}const m=e(i,[["render",l]]);export{_ as __pageData,m as default};
